const contactForm=document.getElementById("contact-form");contactForm&&contactForm.addEventListener("submit",async e=>{e.preventDefault();const t=document.getElementById("response-msg");t.innerText="Envoi en cours...";const n={name:document.getElementById("name").value,email:document.getElementById("email").value,message:document.getElementById("message").value};try{const e=await fetch("https://hugo-contact.mcugnolio-662.workers.dev",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(n)});e.ok?(responseMsg.textContent="Merci pour votre message, nous vous répondrons au plus tôt.",responseMsg.className="contact-success-msg",contactForm.reset()):(responseMsg.textContent="Erreur lors de l'envoi. Réessayez plus tard.",responseMsg.className="text-danger small mt-3 text-center")}catch{t.innerHTML="<span style='color: red;'>Impossible de joindre le serveur.</span>"}})